namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public int InstructorId { get; set; }
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of abstract structures, quantities, and patterns through rigorous proof and analysis." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Critical reading, writing, and analysis of literature and language across cultures and time periods." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces governing the natural world." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examination of past events, societies, and civilizations to understand the present and inform the future." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Ada Lovelace", Title = "Professor of Computer Science", Bio = "Specializes in algorithms and programming language theory with over 15 years of teaching experience. Published author of numerous papers on computational complexity.", Email = "alovelace@university.edu" },
            new() { Id = 2, Name = "Dr. Alan Turing", Title = "Associate Professor of Computer Science", Bio = "Expert in artificial intelligence and machine learning. Leads the university's AI research lab and has received multiple grants for groundbreaking research.", Email = "aturing@university.edu" },
            new() { Id = 3, Name = "Dr. Emmy Noether", Title = "Professor of Mathematics", Bio = "Renowned for contributions to abstract algebra and theoretical physics. Recipient of the Distinguished Teaching Award three years running.", Email = "enoether@university.edu" },
            new() { Id = 4, Name = "Dr. William Shakespeare", Title = "Professor of English", Bio = "Focuses on Renaissance literature and creative writing. Has published five novels and mentors students in the university's creative writing program.", Email = "wshakespeare@university.edu" },
            new() { Id = 5, Name = "Dr. Marie Curie", Title = "Professor of Physics", Bio = "Conducts research in nuclear physics and radiochemistry. Directs the university's radiation science laboratory and advises graduate students.", Email = "mcurie@university.edu" },
            new() { Id = 6, Name = "Dr. Howard Zinn", Title = "Associate Professor of History", Bio = "Specializes in American social movements and labor history. Known for engaging lecture style and commitment to primary source analysis.", Email = "hzinn@university.edu" },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, data structures, and basic object-oriented programming. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00â€“9:50 AM", Location = "Science Hall 201", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Prerequisites: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30 AMâ€“12:00 PM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, Code = "CS 310", Title = "Artificial Intelligence", Description = "Introduction to AI concepts including search algorithms, knowledge representation, machine learning fundamentals, and neural networks. Includes hands-on projects with real-world datasets.", Credits = 3, Schedule = "Mon/Wed 2:00â€“3:30 PM", Location = "Tech Center 110", DepartmentId = 1, InstructorId = 2, IsFeatured = true },
            new() { Id = 4, Code = "CS 350", Title = "Software Engineering", Description = "Principles of software development including requirements analysis, system design, testing, and project management. Students work in teams on a semester-long project.", Credits = 3, Schedule = "Tue/Thu 1:00â€“2:30 PM", Location = "Tech Center 205", DepartmentId = 1, InstructorId = 2 },

            // Mathematics
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics. Graphing calculator required.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00â€“10:50 AM", Location = "Math Building 101", DepartmentId = 2, InstructorId = 3, IsFeatured = true },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Emphasis on both computational techniques and theoretical understanding.", Credits = 3, Schedule = "Tue/Thu 9:00â€“10:30 AM", Location = "Math Building 203", DepartmentId = 2, InstructorId = 3 },
            new() { Id = 7, Code = "MATH 301", Title = "Abstract Algebra", Description = "Groups, rings, fields, and their homomorphisms. Explores symmetry, number theory applications, and the algebraic structures underlying modern mathematics.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00â€“1:50 PM", Location = "Math Building 305", DepartmentId = 2, InstructorId = 3 },

            // English
            new() { Id = 8, Code = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop clear, persuasive writing skills through essay composition, peer review, and revision. Covers argumentation, research methods, and citation practices.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00â€“11:50 AM", Location = "Humanities Hall 102", DepartmentId = 3, InstructorId = 4 },
            new() { Id = 9, Code = "ENG 220", Title = "World Literature", Description = "Survey of significant literary works from diverse cultures and time periods. Explores themes of identity, power, and human experience across genres.", Credits = 3, Schedule = "Tue/Thu 2:00â€“3:30 PM", Location = "Humanities Hall 210", DepartmentId = 3, InstructorId = 4, IsFeatured = true },

            // Physics
            new() { Id = 10, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments. Co-requisite: MATH 101.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00â€“8:50 AM + Thu Lab 2:00â€“4:50 PM", Location = "Physics Lab 100", DepartmentId = 4, InstructorId = 5 },
            new() { Id = 11, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Wave-particle duality, SchrĂ¶dinger equation, quantum states, and measurement theory. Prerequisites: PHYS 101, MATH 201.", Credits = 3, Schedule = "Tue/Thu 10:00â€“11:30 AM", Location = "Physics Lab 310", DepartmentId = 4, InstructorId = 5, IsFeatured = true },

            // History
            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period. Emphasizes primary source analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00â€“10:50 AM", Location = "Liberal Arts 205", DepartmentId = 5, InstructorId = 6 },
            new() { Id = 13, Code = "HIST 250", Title = "Modern American History", Description = "United States history from Reconstruction to the present, focusing on social movements, political change, and cultural transformation.", Credits = 3, Schedule = "Tue/Thu 11:00 AMâ€“12:30 PM", Location = "Liberal Arts 301", DepartmentId = 5, InstructorId = 6 },
        };
    }

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Instructor> GetInstructors() => _instructors;

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public IReadOnlyList<Course> SearchCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollment(EnrollmentRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.StudentName) ||
            string.IsNullOrWhiteSpace(request.StudentId) ||
            request.CourseId <= 0 ||
            GetCourse(request.CourseId) is null)
        {
            return false;
        }

        _enrollments.Add(request);
        return true;
    }
}

