        <p>Your enrollment request has been received. You will be notified of your enrollment status by email.</p>
        <hr />
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    if (ValidationError is not null)
    {
        <div class="alert alert-danger">@ValidationError</div>
    }

    <form method="post" class="col-md-8">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                   value="@Model.StudentName" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                   value="@Model.StudentId" required placeholder="e.g. S12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="Model.CourseId" required>
                <option value="">â€” Select a course â€”</option>
                @foreach (var course in Catalog.GetAllCourses())
