    {
        // Check if this is a POST (form was submitted)
        if (!string.IsNullOrWhiteSpace(Model.StudentName) && !string.IsNullOrWhiteSpace(Model.StudentId) && Model.CourseId > 0)
        {
            if (Catalog.SubmitEnrollment(Model))
