@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Course List</a>
}
else
{
    <PageTitle>@course.Code â€” @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@dept?.Id">@dept?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code â€” @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule &amp; Location</h4>
            <dl class="row">
                <dt class="col-sm-3">Schedule</dt>
                <dd class="col-sm-9">@course.Schedule</dd>
                <dt class="col-sm-3">Location</dt>
                <dd class="col-sm-9">@course.Location</dd>
                <dt class="col-sm-3">Credits</dt>
                <dd class="col-sm-9">@course.Credits</dd>
            </dl>
        </div>

        <div class="col-md-4">
            @if (instructor is not null)
            {
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@instructor.Name</h6>
                        <p class="card-text"><em>@instructor.Title</em></p>
                        <p class="card-text">@instructor.Bio</p>
                        <p class="card-text"><small class="text-muted">@instructor.Email</small></p>
                    </div>
                </div>
            }

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? dept;
    private Instructor? instructor;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
        {
            dept = Catalog.GetDepartment(course.DepartmentId);
            instructor = Catalog.GetInstructor(course.InstructorId);
        }
    }
}

