    [SupplyParameterFromForm] public EnrollmentRequest? Model { get; set; }
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private bool Submitted { get; set; }
    private string? ValidationError { get; set; }

    protected override void OnInitialized()
    {
        Model ??= new();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (Model is null) return;

        if (!string.IsNullOrWhiteSpace(Model.StudentName) && !string.IsNullOrWhiteSpace(Model.StudentId) && Model.CourseId > 0)
        {
            if (Catalog.SubmitEnrollment(Model))
            {
                Submitted = true;
            }
            else
            {
                ValidationError = "Please fill out all fields and select a valid course.";
            }
        }
    }
}

